function generateDistinctPermutations(multiset: number[]): number[][] {
    multiset.sort((a, b) => a - b);
    const used = new Array(multiset.length).fill(false);
    const result: number[][] = [];
    const path: number[] = [];
    const backtrack = () => {
        if (path.length === multiset.length) {
            result.push([...path]);
            return;
        }
        for (let i = 0; i < multiset.length; i++) {
            if (used[i]) continue;
            if (i > 0 && multiset[i] === multiset[i - 1] && !used[i - 1]) continue;
            used[i] = true;
            path.push(multiset[i]);
            backtrack();
            path.pop();
            used[i] = false;
        }
    };
    backtrack();
    return result;
}

function solve(n: number): number {
    const nStr = n.toString();
    const lenN = nStr.length;
    const subsets: number[][] = [];
    for (let mask = 1; mask < (1 << 9); mask++) {
        const set: number[] = [];
        for (let i = 0; i < 9; i++) {
            if (mask & (1 << i)) {
                set.push(i + 1);
            }
        }
        subsets.push(set);
    }

    const candidates: bigint[] = [];

    for (const S of subsets) {
        const L = S.reduce((sum, val) => sum + val, 0);
        if (L === 0) continue;

        if (L % 2 === 0) {
            if (S.every(d => d % 2 === 0)) {
                const multiset: number[] = [];
                for (const d of S) {
                    for (let i = 0; i < d / 2; i++) {
                        multiset.push(d);
                    }
                }
                multiset.sort((a, b) => a - b);
                if (L < lenN) {
                    continue;
                } else if (L > lenN) {
                    const AStr = multiset.join('');
                    const rev = AStr.split('').reverse().join('');
                    const entireStr = AStr + rev;
                    const candidate = BigInt(entireStr);
                    if (candidate > BigInt(n)) {
                        candidates.push(candidate);
                    }
                } else {
                    const perms = generateDistinctPermutations(multiset);
                    for (const perm of perms) {
                        const AStr = perm.join('');
                        const rev = AStr.split('').reverse().join('');
                        const entireStr = AStr + rev;
                        const candidate = BigInt(entireStr);
                        if (candidate > BigInt(n)) {
                            candidates.push(candidate);
                            break;
                        }
                    }
                }
            }
        } else {
            let oddCount = 0;
            let oddDigit = 0;
            for (const d of S) {
                if (d % 2 !== 0) {
                    oddCount++;
                    oddDigit = d;
                }
            }
            if (oddCount !== 1) {
                continue;
            }
            const multiset: number[] = [];
            for (const d of S) {
                if (d % 2 === 0) {
                    for (let i = 0; i < d / 2; i++) {
                        multiset.push(d);
                    }
                } else {
                    for (let i = 0; i < (d - 1) / 2; i++) {
                        multiset.push(d);
                    }
                }
            }
            multiset.sort((a, b) => a - b);
            if (L < lenN) {
                continue;
            } else if (L > lenN) {
                const AStr = multiset.join('');
                const rev = AStr.split('').reverse().join('');
                const entireStr = AStr + oddDigit + rev;
                const candidate = BigInt(entireStr);
                if (candidate > BigInt(n)) {
                    candidates.push(candidate);
                }
            } else {
                const perms = generateDistinctPermutations(multiset);
                for (const perm of perms) {
                    const AStr = perm.join('');
                    const rev = AStr.split('').reverse().join('');
                    const entireStr = AStr + oddDigit + rev;
                    const candidate = BigInt(entireStr);
                    if (candidate > BigInt(n)) {
                        candidates.push(candidate);
                        break;
                    }
                }
            }
        }
    }

    if (candidates.length === 0) {
        return -1;
    }

    candidates.sort((a, b) => a < b ? -1 : a > b ? 1 : 0);
    const ans = candidates[0];
    if (ans <= BigInt(Number.MAX_SAFE_INTEGER)) {
        return Number(ans);
    }
    return Number(ans);
}
