function solve(n: number): number {
    if (n < 0) throw new Error("n must be non-negative");
    const n_str = String(n);
    const n_len = n_str.length;

    const all_digits = [1, 2, 3, 4, 5, 6, 7, 8, 9];
    const bigZero = BigInt(0);
    let global_candidate = BigInt(10) ** BigInt(50);

    const reverse = (s: string) => s.split('').reverse().join('');

    const generateSmallestFromCounts = (counts: number[]) => {
        let arr: number[] = [];
        for (let d = 1; d <= 9; d++) {
            const cnt = counts[d - 1];
            for (let j = 0; j < cnt; j++) {
                arr.push(d);
            }
        }
        arr.sort((a, b) => a - b);
        return arr.join('');
    };

    for (let mask = 1; mask < (1 << 9); mask++) {
        let set: number[] = [];
        for (let i = 0; i < 9; i++) {
            if (mask & (1 << i)) {
                set.push(i + 1);
            }
        }

        let count_odd = 0;
        for (let d of set) {
            if (d % 2 === 1) count_odd++;
        }
        if (count_odd > 1) continue;

        const total_length = set.reduce((sum, d) => sum + d, 0);
        if (total_length === 0) continue;

        let center_char = '';
        if (count_odd === 1) {
            for (let d of set) {
                if (d % 2 === 1) {
                    center_char = String(d);
                    break;
                }
            }
        }

        const counts_left = new Array(9).fill(0);
        for (let d of set) {
            if (d % 2 === 0) {
                counts_left[d - 1] = d / 2;
            } else {
                counts_left[d - 1] = (d - 1) / 2;
            }
        }

        const left_half_length = (total_length - (center_char ? 1 : 0)) / 2;
        let candidate_set = BigInt(10) ** BigInt(50);

        if (total_length < n_len) {
            continue;
        } else if (total_length > n_len) {
            const smallest_left = generateSmallestFromCounts(counts_left);
            const entire_str = smallest_left + center_char + reverse(smallest_left);
            candidate_set = BigInt(entire_str);
        } else {
            let candidate_local = BigInt(10) ** BigInt(50);
            const counts = [...counts_left];
            const L = total_length;
            let str_n = n_str;

            const dfs = (i: number, counts: number[], current: string) => {
                if (i === left_half_length) {
                    const full_left = current;
                    const entire_str = full_left + center_char + reverse(full_left);
                    const num = BigInt(entire_str);
                    if (num > BigInt(n)) {
                        if (num < candidate_local) {
                            candidate_local = num;
                        }
                    }
                    return;
                }

                const current_prefix = current;
                if (current_prefix.length < i) {
                    throw new Error("Unexpected: current_prefix.length < i");
                }
                const n_prefix = str_n.substring(0, i);
                if (current_prefix < n_prefix) {
                    return;
                }
                if (current_prefix > n_prefix) {
                    let remaining_arr: number[] = [];
                    for (let d = 1; d <= 9; d++) {
                        const cnt = counts[d - 1];
                        for (let j = 0; j < cnt; j++) {
                            remaining_arr.push(d);
                        }
                    }
                    remaining_arr.sort((a, b) => a - b);
                    const smallest_remaining = remaining_arr.join('');
                    const full_left = current + smallest_remaining;
                    const entire_str = full_left + center_char + reverse(full_left);
                    const num_val = BigInt(entire_str);
                    if (num_val < candidate_local) {
                        candidate_local = num_val;
                    }
                    return;
                }

                const min_char = parseInt(str_n[i]);
                for (let d = 1; d <= 9; d++) {
                    if (counts[d - 1] <= 0) continue;
                    if (d < min_char) continue;

                    let new_counts = [...counts];
                    new_counts[d - 1]--;
                    let new_current = current + String(d);

                    if (d > min_char) {
                        let remaining_arr: number[] = [];
                        for (let d_in = 1; d_in <= 9; d_in++) {
                            const cnt = new_counts[d_in - 1];
                            for (let j = 0; j < cnt; j++) {
                                remaining_arr.push(d_in);
                            }
                        }
                        remaining_arr.sort((a, b) => a - b);
                        const smallest_remaining = remaining_arr.join('');
                        const full_left = new_current + smallest_remaining;
                        const entire_str = full_left + center_char + reverse(full_left);
                        const num_val = BigInt(entire_str);
                        if (num_val < candidate_local) {
                            candidate_local = num_val;
                        }
                        break;
                    } else {
                        dfs(i + 1, new_counts, new_current);
                    }
                }
            };

            dfs(0, counts, '');
            candidate_set = candidate_local;
        }

        if (candidate_set < global_candidate) {
            global_candidate = candidate_set;
        }
    }

    const candidateNumber = Number(global_candidate);
    if (candidateNumber <= Number.MAX_SAFE_INTEGER) {
        return candidateNumber;
    } else {
        throw new Error("The found candidate is not safely representable as a JavaScript number");
    }
}
